&lt;/li&gt;
&lt;li data-start=&quot;1543&quot; data-end=&quot;1595&quot;&gt;
&lt;p data-start=&quot;1545&quot; data-end=&quot;1595&quot;&gt;Conduct venipuncture as requested by physicians.&lt;/p&gt;
&lt;/li&gt;
&lt;li data-start=&quot;1596&quot; data-end=&quot;1653&quot;&gt;
&lt;p data-start=&quot;1598&quot; data-end=&quot;1653&quot;&gt;Maintain accurate specimen records and documentation.&lt;/p&gt;
&lt;/li&gt;
&lt;li data-start=&quot;1654&quot; data-end=&quot;1707&quot;&gt;
&lt;p data-start=&quot;1656&quot; data-end=&quot;1707&quot;&gt;Monitor and maintain laboratory supply inventory.&lt;/p&gt;
